// Some portions generated by Claude
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.io.File;
import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * W3C SPARQL 1.1 sq08: an aggregate sub-SELECT is evaluated once, in its own scope — joining its result with an outer
 * pattern must not turn the global aggregate into a correlated per-binding aggregate.
 */
class LmdbSubqueryAggregateScopeTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI P = VF.createIRI("http://www.example.org/schema#p");

	@Test
	void aggregateSubqueryStaysGlobal(@TempDir File dataDir) {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc"));
		SailRepository repository = new SailRepository(store);
		repository.init();
		try {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin();
				IRI a = VF.createIRI("http://www.example.org/instance#a");
				IRI b = VF.createIRI("http://www.example.org/instance#b");
				connection.add(a, P, VF.createLiteral(1));
				connection.add(a, P, VF.createLiteral(2));
				connection.add(b, P, VF.createLiteral(3));
				connection.commit();
			}
			try (SailRepositoryConnection connection = repository.getConnection()) {
				List<BindingSet> rows = QueryResults.asList(connection.prepareTupleQuery(String.join("\n",
						"prefix ex: <http://www.example.org/schema#>",
						"select ?x ?max where {",
						"  { select (max(?y) as ?max) where { ?x ex:p ?y } }",
						"  ?x ex:p ?max",
						"}")).evaluate());
				assertEquals(1, rows.size(),
						() -> "The aggregate sub-SELECT must be computed once over the whole store (max=3), not "
								+ "per outer binding: " + rows);
				assertEquals("3", rows.get(0).getValue("max").stringValue());
				assertEquals("http://www.example.org/instance#b", rows.get(0).getValue("x").stringValue());
			}
		} finally {
			repository.shutDown();
		}
	}
}
